parameters.jsCode:
const input = $json;
return [{ json: {
  chat_id: input.chat_id,
  count: input.config?.xp_maps?.count || 50,
  id_start: input.id_ranges?.xp_maps?.start || 500000,
  gemini_key: input.gemini_key || 'AIzaSyAT4U4SNPm9rgR5nogX3HTcESFL_bg9uHo'
}}];

const config = $('Config').first().json;

// Generate unique map codes in format ####-####-####
const usedCodes = new Set();
const forbiddenPatterns = ['0000-0000-0000', '1111-1111-1111', '1234-1234-1234', '1234-5678-9012'];

function generateCode() {
  let code;
  let attempts = 0;
  do {
    const p1 = String(Math.floor(1000 + Math.random() * 9000));
    const p2 = String(Math.floor(1000 + Math.random() * 9000));
    const p3 = String(Math.floor(1000 + Math.random() * 9000));
    code = `${p1}-${p2}-${p3}`;
    attempts++;
    // Check for forbidden patterns (same blocks)
    if (p1 === p2 && p2 === p3) continue;
    if (forbiddenPatterns.includes(code)) continue;
  } while (usedCodes.has(code) && attempts < 100);
  usedCodes.add(code);
  return code;
}

// Map themes for variety
const themes = [
  { name: 'Tropical Paradise', tags: ['tropical', 'beach', 'xp'], desc: 'A sunny beach island perfect for XP farming' },
  { name: 'Neon City', tags: ['neon', 'city', 'cyberpunk'], desc: 'Futuristic city with neon lights and XP zones' },
  { name: 'Ancient Temple', tags: ['temple', 'ancient', 'adventure'], desc: 'Mysterious temple ruins with hidden XP rewards' },
  { name: 'Space Station', tags: ['space', 'sci-fi', 'zero-g'], desc: 'Orbital station with zero gravity XP challenges' },
  { name: 'Haunted Mansion', tags: ['horror', 'mansion', 'spooky'], desc: 'Creepy mansion with XP secrets in every room' },
  { name: 'Crystal Caves', tags: ['caves', 'crystal', 'underground'], desc: 'Glowing crystal caverns filled with XP' },
  { name: 'Sky Islands', tags: ['sky', 'floating', 'parkour'], desc: 'Floating islands with parkour XP challenges' },
  { name: 'Volcano Arena', tags: ['volcano', 'lava', 'action'], desc: 'Active volcano with intense XP battles' },
  { name: 'Frozen Tundra', tags: ['ice', 'snow', 'winter'], desc: 'Frozen landscape with hidden XP caches' },
  { name: 'Jungle Expedition', tags: ['jungle', 'nature', 'exploration'], desc: 'Dense jungle with exploration XP rewards' }
];

const maps = [];
for (let i = 0; i < config.count; i++) {
  const theme = themes[i % themes.length];
  const variant = Math.floor(i / themes.length) + 1;

  maps.push({
    json: {
      id: config.id_start + i,
      name: `${theme.name} ${variant > 1 ? 'V' + variant : ''}`.trim(),
      description: theme.desc,
      code: generateCode(),
      tags: theme.tags,
      img_file: `${config.id_start + i}.png`,
      _idx: i,
      _theme: theme.name.toLowerCase().replace(/\s+/g, '_'),
      _chat_id: config.chat_id,
      _gemini_key: config.gemini_key
    }
  });
}

return maps;

