parameters.jsCode:
const items = $('Generate Maps').all();
const meta = items[$itemIndex]?.json || {};
const response = $json;

let imageData = null;
let mimeType = 'image/png';

try {
  const parts = response.candidates?.[0]?.content?.parts || [];
  for (const part of parts) {
    if (part.inlineData) {
      imageData = part.inlineData.data;
      mimeType = part.inlineData.mimeType || 'image/png';
      break;
    }
  }
} catch (e) {}

if (imageData) {
  return {
    json: meta,
    binary: {
      image: {
        data: imageData,
        mimeType: mimeType,
        fileName: meta.img_file
      }
    }
  };
}

return { json: { ...meta, _skip: true } };

const meta = $json;
const bin = $input.item.binary || {};
const newBin = {};
if (bin.image) newBin.image = { ...bin.image, fileName: meta.img_file, mimeType: 'image/png' };
return { json: meta, binary: newBin };

const items = $json.items || [];
const finalItems = $('Finalize').all();
let chatId = items[0]?._chat_id || 0;

// CSV: name, description, image, code, tags
const csv = ['name,description,image,code,tags'];
for (const item of items) {
  if (!item._skip) {
    const tagsStr = JSON.stringify(item.tags || []);
    csv.push(`"${(item.name||'').replace(/"/g,'')}","${(item.description||'').replace(/"/g,'')}",${item.img_file},${item.code},"${tagsStr.replace(/"/g, '""')}"`);
  }
}

// Collect binaries
const binData = {};
const keys = [];
for (const f of finalItems) {
  if (f.binary?.image) {
    binData[f.json.img_file] = f.binary.image;
    keys.push(f.json.img_file);
  }
}

return [
  { json: { type: 'csv', chat_id: chatId, count: keys.length }, binary: { file: { data: Buffer.from(csv.join('\n')).toString('base64'), mimeType: 'text/csv', fileName: 'xp_maps.csv' } } },
  { json: { type: 'zip', chat_id: chatId, count: keys.length, keys: keys.join(',') }, binary: binData }
];
